import React, { useEffect, useState } from "react";
import axios from "axios";
import "bootstrap/dist/css/bootstrap.min.css";
import Pagination from "../components/Pagination";

export default function VentasHistorial() {
  const [ventas, setVentas] = useState([]);
  const [currentPage, setCurrentPage] = useState(1);
  const itemsPerPage = 5; // cantidad de ventas por página

  useEffect(() => {
    cargarHistorial();
  }, []);

  const cargarHistorial = async () => {
    try {
      const res = await axios.get("http://localhost:5000/api/ventas/historial");
      setVentas(res.data);
    } catch (error) {
      console.error("❌ Error al cargar historial:", error);
    }
  };

  // Paginación
  const indexLast = currentPage * itemsPerPage;
  const indexFirst = indexLast - itemsPerPage;
  const ventasMostradas = ventas.slice(indexFirst, indexLast);

  return (
    <div className="container mt-4">
      <h3>📊 Historial de Ventas</h3>

      <div className="table-responsive">
        <table className="table table-bordered table-striped mt-3 text-center">
          <thead className="table-dark">
            <tr>
              <th>Factura</th>
              <th>Fecha</th>
              <th>Cliente</th>
              <th>Subtotal</th>
              <th>IVA</th>
              <th>Total</th>
            </tr>
          </thead>
          <tbody>
            {ventasMostradas.length > 0 ? (
              ventasMostradas.map((v) => (
                <tr key={v.VentaID}>
                  <td>{v.NumeroSecuencia}</td>
                  <td>{new Date(v.Fecha).toLocaleString()}</td>
                  <td>{v.Cliente}</td>
                  <td>${v.Subtotal.toFixed(2)}</td>
                  <td>${v.IVA.toFixed(2)}</td>
                  <td className="fw-bold">${v.Total.toFixed(2)}</td>
                </tr>
              ))
            ) : (
              <tr>
                <td colSpan="6">No hay ventas registradas.</td>
              </tr>
            )}
          </tbody>
        </table>
      </div>

      {/* Componente de paginación reutilizable */}
      <Pagination
        totalItems={ventas.length}
        itemsPerPage={itemsPerPage}
        currentPage={currentPage}
        onPageChange={setCurrentPage}
      />
    </div>
  );
}
